INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$What is Pallyy used for?$q$, $q$Pallyy is used for scheduling and managing social media posts across multiple platforms, with a particular focus on visual Instagram grid planning.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Is Pallyy free?$q$, $q$Yes, Pallyy has a free plan covering 1 social account and 15 posts per month; paid plans start at $15/month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$What platforms does Pallyy support?$q$, $q$Instagram, Facebook, TikTok, X, LinkedIn, Pinterest, YouTube and Google Business Profile.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Who owns Pallyy?$q$, $q$Pallyy was founded by Tim Bennetto in 2019 and is based in Melbourne, Australia, operating as a self-funded, bootstrapped company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Does Pallyy have a link-in-bio tool?$q$, $q$Yes, Pallyy includes a built-in link-in-bio landing page builder.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$How is Pallyy different from Later?$q$, $q$Both focus on visual Instagram planning, but Pallyy bundles inbox management and link-in-bio tools at generally lower price points than Later.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Does Pallyy support team collaboration?$q$, $q$Yes, approval workflows, shared calendars and multi-user access are available on the Agency and Scale plans.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Does Pallyy offer analytics?$q$, $q$Yes, engagement and performance analytics are included, with data retention that increases on higher tiers.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Agency client management$q$, $q$Manage scheduling, approvals and inboxes for multiple client social accounts from one dashboard.$q$, $q$Social media agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Creator feed curation$q$, $q$Plan and preview an Instagram feed visually before publishing to keep a consistent aesthetic.$q$, $q$Content creators and influencers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Small business social presence$q$, $q$Schedule and track posts across multiple platforms without a dedicated social media team.$q$, $q$Small business owners and marketers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["1 social account","15 posts per month","1 user","200MB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Starter$q$, $q$$15/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["1 social set","20 posts per month","1 user"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Pro$q$, $q$$25/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["1 social set","Unlimited posts","1 user","AI captions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Agency$q$, $q$$99/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["10 social sets","Unlimited posts","3 users","Approval workflows"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$Scale$q$, $q$$199/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["30 social sets","Unlimited posts","10 users","50GB storage"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pallyy is a social media scheduling and management tool founded in 2019 and based in Melbourne, Australia. It is best known for its visual grid planner, which lets users lay out and preview Instagram posts as a grid before they go live, a workflow that has made it popular with agencies and creators who care about feed aesthetics.$q$, $q$Beyond Instagram, Pallyy supports scheduling across Facebook, TikTok, X, LinkedIn, Pinterest, YouTube and Google Business Profile, and bundles a social inbox, analytics, AI caption writing and a link-in-bio tool into one subscription rather than requiring separate add-on products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The visual grid planner is Pallyy's headline feature, letting users drag and drop scheduled posts to preview how an Instagram feed will look before anything is published. This is paired with multi-platform scheduling and auto-publishing, an AI-assisted caption generator, and approval workflows so agencies can route drafts to clients for sign-off.$q$, $q$A unified social inbox consolidates comments, direct messages and reviews from connected platforms, while built-in analytics track engagement over time. A link-in-bio landing page builder and shared team calendars round out the toolset for agencies managing multiple client accounts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b464dfda-017c-4855-b431-a807ed2c1ace', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pallyy uses a freemium model. The free plan includes 1 social account and 15 posts per month. Paid plans start with Starter at $15/month, then Pro at $25/month, Agency at $99/month, and Scale at $199/month, each raising the number of social accounts (called social sets), users, storage and unlocked features like unlimited posts, AI captions and approval workflows.$q$, $q$Annual billing offers savings of up to 25 percent versus paying monthly. Agencies that need more capacity than their plan includes can add extra social sets or user seats for a flat monthly add-on fee rather than upgrading to the next full tier.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Drag-and-drop document editor$q$, $q$Build proposals, quotes and contracts from a reusable content and template library.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Legally binding e-signatures$q$, $q$Collect ESIGN/UETA and eIDAS-compliant signatures on proposals, contracts, quotes and forms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Real-time document tracking$q$, $q$See when documents are opened, how long each page is viewed, and signing status as it happens.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$CRM integrations$q$, $q$Connect natively with Salesforce, HubSpot, Pipedrive, Zoho and other CRMs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Built-in payment collection$q$, $q$Accept payment directly within a signed document via Stripe, PayPal and other gateways.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Configure-price-quote (CPQ)$q$, $q$Generate accurate sales quotes from product catalogs on Enterprise plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Approval workflows and deal rooms$q$, $q$Route documents for internal approval and manage collaborative deal spaces with prospects.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$API and webhooks$q$, $q$Automate document generation and status updates through PandaDoc's API.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$All-in-one document creation, signing and payment collection reduces tool sprawl$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Deep CRM integrations streamline sales workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Real-time tracking shows exactly how recipients engage with documents$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Free plan and relatively affordable Starter tier for small teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Large template and content library speeds up proposal creation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Per-seat pricing can get expensive for larger sales teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Advanced features like CPQ and SSO require custom Enterprise pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Document limits on the Free plan (60/year) are restrictive for active use$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Learning curve for building complex conditional workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Some users report formatting quirks when importing from Word or PDF$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$What is PandaDoc used for?$q$, $q$Creating, sending, tracking and e-signing sales proposals, quotes, contracts and forms.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Is PandaDoc free?$q$, $q$Yes, a free plan is capped at 60 documents per year with unlimited e-signatures; paid plans start at $19/month per seat.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Is PandaDoc's e-signature legally binding?$q$, $q$Yes, PandaDoc e-signatures are designed to comply with ESIGN and UETA in the US and eIDAS in the EU.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Who founded PandaDoc?$q$, $q$Mikita Mikado and Sergey Barysiuk founded PandaDoc in 2011; it is now headquartered in San Francisco.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Does PandaDoc integrate with CRMs?$q$, $q$Yes, with native integrations for Salesforce, HubSpot, Pipedrive, Zoho and others.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$How is PandaDoc different from DocuSign?$q$, $q$PandaDoc bundles document creation, CRM integration and payments alongside e-signature, while DocuSign is primarily focused on e-signature and broader agreement management.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Does PandaDoc support payment collection?$q$, $q$Yes, Business and Enterprise plans let recipients pay directly within a signed document.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Can PandaDoc build quotes automatically?$q$, $q$Yes, CPQ tools on the Enterprise plan let sales teams generate quotes from product catalogs.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Sales proposal and quote automation$q$, $q$Build, send and track proposals and quotes tied directly to CRM deal records.$q$, $q$Sales teams and reps$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Contract and HR document e-signature$q$, $q$Route offer letters, NDAs and vendor contracts for compliant electronic signature.$q$, $q$HR and legal teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Agency client onboarding$q$, $q$Manage proposals, contracts and payment collection in shared deal rooms with clients.$q$, $q$Agencies and consultants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["60 documents per year","Unlimited e-signatures","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Starter$q$, $q$$19/month per seat$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited document uploads and e-signatures","Real-time tracking","Mobile app access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Business$q$, $q$$49/month per seat$q$, $q$monthly or annual$q$, NULL, $q$["CRM integrations","Custom branding and content library","Up to 3 deal rooms","Payment collection"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["CPQ","Workflow automation","SSO","API access","Data residency options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PandaDoc is a document automation platform founded in 2011 and headquartered in San Francisco, California. It helps sales, HR and legal teams build, send, track and e-sign documents such as proposals, quotes, contracts and internal forms from a single editor.$q$, $q$The platform is positioned as an all-in-one document workflow tool rather than a single-purpose e-signature product, combining content creation, CRM integrations and payment collection alongside legally binding electronic signatures.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$A drag-and-drop editor and reusable content library speed up building proposals and contracts, while legally binding e-signatures let recipients sign from any device. Real-time tracking shows when a document is opened, how long each page is viewed, and whether it has been signed.$q$, $q$Native CRM integrations with Salesforce, HubSpot and Pipedrive connect document workflows to sales pipelines, built-in payment collection lets signed documents trigger a charge, and Enterprise-tier configure-price-quote (CPQ) tools let sales teams generate accurate quotes directly from product catalogs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed06026a-8e0a-484f-bfd3-2d07240984eb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PandaDoc is priced per seat on a freemium model. The free plan is capped at 60 documents per year with unlimited e-signatures. The Starter plan begins at $19/month per seat, and the Business plan, PandaDoc's most popular tier, is priced around $49/month per seat and adds CRM integrations, deal rooms and payment collection.$q$, $q$The Enterprise plan is custom-priced and adds CPQ, workflow automation, SSO, API access and data residency options. Annual billing offers a significant discount compared to paying monthly, and documents beyond a plan's included limit are billed a few dollars each.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Dev/test/live workflow$q$, $q$Every site gets standardized development, test and live environments with one-click deploys.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Multidev environments$q$, $q$Spin up isolated, on-demand clones of a site for testing individual feature branches.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Git-based version control and Terminus CLI$q$, $q$Automate deployments and integrate CMS workflows with CI/CD pipelines.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Built-in global CDN$q$, $q$Edge caching included on all Site Plans to speed up page delivery.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Automated backups$q$, $q$Scheduled backups with one-click restore for WordPress and Drupal sites.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Native WordPress and Drupal support$q$, $q$Manage both CMS platforms under the same WebOps environment model.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Enterprise compliance$q$, $q$SOC 2, GDPR and FERPA-aligned infrastructure for regulated organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Traffic-based Site Plans$q$, $q$Pricing scales with monthly visits and pages served, with overage protection on annual plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Strong DevOps workflow (dev/test/live, multidev) built into every plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Supports both WordPress and Drupal under one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Good fit for agencies managing many client sites via portfolio tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Solid compliance credentials for enterprise, government and education clients$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Free sandbox workspace available for evaluation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Pricing based on visits and pages served can be unpredictable during traffic spikes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$No low-cost plans for small hobbyist sites compared to shared hosting$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Elite-tier and higher Workspace pricing requires contacting sales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Steeper learning curve for teams unfamiliar with Git-based workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Add-on costs for extra domains or containers can increase total spend$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$What is Pantheon used for?$q$, $q$Managed hosting and WebOps workflow automation for WordPress and Drupal sites.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Does Pantheon support both Drupal and WordPress?$q$, $q$Yes, both are first-class citizens on the platform with the same environment model.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$How much does Pantheon cost?$q$, $q$Site Plans start around $55/month for Basic and scale with traffic; a free sandbox workspace is available for testing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$When was Pantheon founded?$q$, $q$2010, and it is headquartered in San Francisco, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$What is a multidev environment?$q$, $q$An isolated, on-demand clone of a site's codebase and database used to test feature branches in isolation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Does Pantheon include a CDN?$q$, $q$Yes, a global CDN is included on all Site Plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Who are Pantheon's main competitors?$q$, $q$WP Engine, Kinsta and Acquia.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Is Pantheon good for agencies?$q$, $q$Yes, its portfolio and multi-site management tools are designed for agencies and enterprises managing many sites.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Agency multi-site hosting$q$, $q$Host and manage many client WordPress or Drupal sites with consistent workflows and portfolio tools.$q$, $q$Digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Enterprise compliant web hosting$q$, $q$Run marketing and content sites that require uptime guarantees and compliance certifications.$q$, $q$Enterprise IT and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Git-based CMS development$q$, $q$Adopt CI/CD-style workflows for WordPress or Drupal development with dev/test/live environments.$q$, $q$Web development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Silver Workspace$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["2 sandbox sites","Git-based CI/CD","Terminus CLI","Basic chat support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Basic Site Plan$q$, $q$$55/month$q$, $q$monthly or annual$q$, NULL, $q$["25K monthly visits","1 app container","5 domains"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Performance Small$q$, $q$$200/month$q$, $q$monthly or annual$q$, NULL, $q$["35K monthly visits","1 app container","10 domains"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Performance Medium$q$, $q$$350/month$q$, $q$monthly or annual$q$, NULL, $q$["70K monthly visits","2 app containers","15 domains"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Performance Large$q$, $q$$700/month$q$, $q$monthly or annual$q$, NULL, $q$["150K monthly visits","3 app containers","35 domains"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Performance XL$q$, $q$$1,150/month$q$, $q$monthly or annual$q$, NULL, $q$["300K monthly visits","4 app containers","70 domains"]$q$::jsonb, 5);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$Elite$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Unlimited visits","4+ app containers","270 domains","99.95% SLA"]$q$::jsonb, 6);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pantheon is a WebOps platform founded in 2010 and headquartered in San Francisco, California. It provides managed hosting and standardized development workflows for WordPress and Drupal sites, aiming to bring modern DevOps discipline to CMS operations.$q$, $q$Rather than acting as a generic web host, Pantheon gives every site a consistent development, test and live environment structure with Git-based version control, making it popular with agencies and enterprises managing many sites at once.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every site on Pantheon gets dev, test and live environments with one-click deploys, plus multidev environments for spinning up isolated clones to test feature branches. A CLI tool called Terminus and Git-based workflows let teams automate deployments and integrate with CI/CD pipelines.$q$, $q$Pantheon also includes a built-in global CDN, automated backups with one-click restores, and compliance credentials such as SOC 2, GDPR and FERPA, which matter for enterprise, education and government customers. Native support for both WordPress and Drupal under one platform is a key differentiator versus WordPress-only hosts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pantheon pricing has two layers: a Workspace plan, which is free at the Silver tier for sandbox sites and moves to custom pricing at Platinum and Diamond for larger organizations, and per-site Site Plans priced by monthly visits and pages served.$q$, $q$Site Plans start at $55/month for Basic and scale through Performance Small ($200/month), Medium ($350/month), Large ($700/month) and XL ($1,150/month), with custom Elite pricing for unlimited-traffic, high-SLA deployments. Annual billing generally includes extra traffic headroom compared to monthly billing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Global payroll processing$q$, $q$Run compliant payroll across 160+ countries via a network of local partners.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Employer of Record (EOR) and PEO$q$, $q$Hire employees compliantly in countries where a company has no local entity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Contractor and freelancer payments$q$, $q$Onboard and pay contractors with per-transaction billing rather than per-employee fees.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Unified workforce dashboard$q$, $q$Consolidate global payroll spend, compliance status and workforce data in one view.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Multi-currency payment rails$q$, $q$Move money in 130+ currencies through banking partners including J.P. Morgan and Citi.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Workforce OS$q$, $q$Centralize HR and org data alongside payroll for a single workforce record.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Payments OS$q$, $q$Consolidate global disbursements and payment operations across entities.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Countrypedia compliance resource$q$, $q$Reference local employment law and payroll requirements across 160+ countries.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Broad country coverage (160+) without needing to set up local entities$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Strong payroll data visibility and consolidation across a global workforce$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Modular products let companies adopt only what they need$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Backed by significant funding and established banking partnerships$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Serves both employees (EOR/PEO) and contractors on one platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Pricing is largely custom and quote-based, making upfront cost comparison difficult$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Aggregator/partner model can mean less direct control than providers with owned entities$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$EOR pricing (roughly $599-$770/employee/month) is on the higher end versus some competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Onboarding and support quality can vary by country due to reliance on local partners$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Not aimed at very small businesses hiring only one or two international employees$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$What is Papaya Global?$q$, $q$A global payroll and workforce management platform offering payroll, EOR/PEO, contractor payments and workforce analytics.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$How many countries does Papaya Global support?$q$, $q$Payroll and compliance coverage across 160+ countries, with payment capability in even more.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$How much does Papaya Global cost?$q$, $q$Payroll starts around $5/employee/month, EOR runs roughly $599-$770/employee/month, and most enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$When was Papaya Global founded?$q$, $q$2016, by Eynat Guez, Ruben Drong and Ofer Herman.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Where is Papaya Global headquartered?$q$, $q$New York City, with a major operations hub in Israel.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Does Papaya Global own local entities in every country?$q$, $q$No, it primarily operates as an aggregator using a network of local partners.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Who are Papaya Global's main competitors?$q$, $q$Deel, Remote, Rippling and Oyster.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Can Papaya Global pay contractors as well as employees?$q$, $q$Yes, it offers dedicated contractor and freelancer payment management billed per transaction.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$International expansion without local entities$q$, $q$Hire compliant employees in new countries through EOR services instead of setting up legal entities.$q$, $q$Enterprise HR and legal teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Global payroll consolidation$q$, $q$Centralize payroll spend, compliance and reporting across many countries in one dashboard.$q$, $q$Finance and payroll leaders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Distributed contractor payments$q$, $q$Onboard and pay a global network of freelancers and contractors compliantly.$q$, $q$Companies with global freelancer networks$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Workforce OS (Payroll)$q$, $q$From $5/employee/month$q$, $q$per employee, monthly$q$, NULL, $q$["Payroll processing","HR data management","Workforce analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Payroll Plus$q$, $q$From $25/employee/month$q$, $q$per employee, monthly$q$, NULL, $q$["Enhanced payroll support","Volume discounts available"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Employer of Record$q$, $q$$599-$770/employee/month$q$, $q$per employee, monthly$q$, NULL, $q$["Compliant international hiring","Premium tier adds dedicated HR support and priority compliance review"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Contractor Payments$q$, $q$$2.50 per transaction$q$, $q$per transaction$q$, NULL, $q$["Contractor onboarding","Compliant global payouts"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$annual contract$q$, NULL, $q$["Multi-product bundling","Payments OS","Custom SLAs"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Papaya Global is a global payroll and workforce management platform founded in 2016 and headquartered in New York City, with a major operations hub in Israel. It combines payroll processing, Employer of Record (EOR) and PEO services, contractor payments and workforce analytics in one platform.$q$, $q$The company primarily operates as an aggregator, coordinating a network of local in-country partners to deliver payroll and employment compliance in more than 160 countries, rather than owning legal entities in every market itself.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Papaya Global's core products include Workforce OS for payroll and HR data, EOR and PEO services for compliant international hiring, and contractor payment management for freelancers and short-term workers, all accessible through a unified dashboard.$q$, $q$The platform emphasizes payment infrastructure, moving money in 130-plus currencies through banking partners such as J.P. Morgan and Citi, and provides consolidated visibility into global workforce spend and compliance status for finance and HR leaders.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ccd5534-faa4-40e5-8b15-5ca13db08e2e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Papaya Global publishes some reference pricing: Payroll starts around $5 per employee per month, Payroll Plus from about $25 per employee per month, and contractor payments are billed per transaction at roughly $2.50 each.$q$, $q$Employer of Record pricing runs approximately $599 to $770 per employee per month depending on service tier and country, and most enterprise deployments across multiple products require a custom quote from Papaya's sales team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Document-style editor$q$, $q$Build forms as flowing documents with inline text, media and fields rather than a rigid grid.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Guided display mode$q$, $q$Present questions one at a time in a conversational format similar to a chat interface.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Built-in payment collection$q$, $q$Accept payments through five gateways, including Stripe and PayPal, on all paid plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Calculation engine$q$, $q$Use Excel-style formulas to build dynamic quotes, pricing and scored quizzes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Conditional logic$q$, $q$Show or hide fields and pages based on a respondent's previous answers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Template library$q$, $q$Start from templates for order forms, bookings, surveys and landing pages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Third-party integrations$q$, $q$Connect to Zapier, Google Sheets, Mailchimp, Slack and more.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Custom domains and branding$q$, $q$Host forms on a custom domain with custom HTML/CSS on higher-tier plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Flexible document-style editor supports rich content, not just simple fields$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Multiple payment gateways included on all paid plans, not limited to the top tier$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Built-in calculation engine handles complex pricing and quoting logic$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Forms can double as landing pages or product pages, reducing the need for a separate site$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Generous free plan for testing before upgrading$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Free plan submission limit (30/month) is low for active use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Custom domain requires the Pro tier or above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Smaller integration ecosystem than larger competitors like Jotform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Learning curve to fully use calculation and conditional-logic features$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Annual submission caps on paid tiers can require plan upgrades as usage grows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$What is Paperform used for?$q$, $q$Building forms, surveys, quizzes, landing pages and payment flows with a flexible, document-style editor.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Is Paperform free?$q$, $q$Yes, a free plan supports 1 user and 30 submissions per month; paid plans start at $24/month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Does Paperform support payments?$q$, $q$Yes, five payment gateways, including Stripe and PayPal, are available on paid plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Who founded Paperform?$q$, $q$Dean and Diony McPherson founded Paperform in 2016 in Sydney, Australia.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$How is Paperform different from Typeform?$q$, $q$Paperform uses a document-style editor with multi-field pages and built-in payments, while Typeform is primarily a one-question-at-a-time conversational format.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Can Paperform calculate prices or quotes?$q$, $q$Yes, it includes an Excel-style calculation engine for dynamic pricing and scored quizzes.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Does Paperform integrate with other tools?$q$, $q$Yes, including Zapier, Google Sheets, Mailchimp and Slack.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Does Paperform offer a custom domain?$q$, $q$Yes, available as an add-on from the Pro plan and included on the Business plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Selling products through an order form$q$, $q$Build a payment-enabled order form that also functions as a product landing page.$q$, $q$Small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Lead-capture landing pages$q$, $q$Create standalone landing pages with embedded forms without needing a separate website.$q$, $q$Agencies and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Scored quizzes and surveys$q$, $q$Use conditional logic and calculations to build interactive quizzes or assessments.$q$, $q$Coaches and course creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["1 user","30 submissions per month","Unlimited forms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Essentials$q$, $q$$24/month ($288/year billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["1 user","1,200 submissions per year","Unlimited forms"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Pro$q$, $q$$49/month ($588/year billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["3 users","12,000 submissions per year","Custom HTML/CSS"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Business$q$, $q$$99/month ($1,188/year billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["5 users (expandable)","120,000 submissions per year","1 custom domain included","SSO"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Unlimited forms, submissions and users","Bespoke functionality"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Paperform is an online form builder founded in 2016 and headquartered in Sydney, Australia. Its editor works more like a document than a traditional grid-based form tool, letting users type content and drop in fields, media and payment blocks inline.$q$, $q$This document-style approach makes Paperform popular for forms that double as landing pages, order forms or proposals, not just plain surveys, appealing especially to small businesses, agencies and course creators.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Paperform combines a flexible WYSIWYG editor with a guided, conversational display mode, an Excel-style calculation engine for quotes and scored quizzes, and conditional logic to show or hide fields based on responses.$q$, $q$Payment collection is built in across five gateways, including Stripe and PayPal, on every paid plan, and integrations with Zapier, Google Sheets, Mailchimp and Slack connect form submissions to the rest of a business's workflow.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Paperform's free plan supports 1 user and 30 submissions per month. Paid plans start with Essentials at $24/month, then Pro at $49/month and Business at $99/month, each raising submission limits, user seats and storage.$q$, $q$An Enterprise tier offers custom pricing with unlimited forms, submissions and users plus bespoke functionality. Annual billing is available on every paid tier at a reduced effective monthly rate compared to paying month to month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Automatic OCR$q$, $q$Extract searchable text from scanned documents automatically on ingest.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$ML-assisted tagging$q$, $q$Get automatic suggestions for tags, correspondents, document types and dates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Full-text search$q$, $q$Search across the extracted text of every archived document.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Multiple ingestion methods$q$, $q$Add documents via a watched consume folder, web upload, email or mobile app.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Document versioning$q$, $q$Track a history of changes and revisions for each archived document.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$REST API$q$, $q$Automate document workflows and integrate with third-party tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Multi-user support$q$, $q$Allow several users to access and manage the same document archive with permissions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Self-hosted deployment$q$, $q$Run entirely on infrastructure the user controls, typically via Docker Compose.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Large, active GitHub community with frequent releases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Full data ownership and privacy since it is self-hosted$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Automatic OCR and machine-learning-based tagging reduce manual filing work$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Lighter resource footprint than heavier enterprise DMS alternatives$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Requires self-hosting expertise, including Docker and server maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$No official vendor support or SLA since it is community-maintained$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Documents are stored unencrypted by default, requiring careful deployment security$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Lacks the advanced workflow automation found in heavier tools like Mayan EDMS$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Initial setup and OCR tuning can require technical troubleshooting$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$What is Paperless-ngx?$q$, $q$A free, open-source, self-hosted document management system for scanning, OCR and archiving documents.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Is Paperless-ngx free?$q$, $q$Yes, it is fully open source under the GPL-3.0 license with no cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Do I need to self-host Paperless-ngx?$q$, $q$Yes, it runs on your own server, NAS or cloud VM, typically via Docker Compose.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Is Paperless-ngx the same as Paperless-ng?$q$, $q$No, Paperless-ngx is a community-maintained fork of Paperless-ng, created in 2022 after the original maintainer stepped back from active development.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Does Paperless-ngx support OCR?$q$, $q$Yes, it automatically OCRs ingested documents and indexes the extracted text for full-text search.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Is Paperless-ngx secure to expose on the internet?$q$, $q$The maintainers recommend against it, since documents are stored unencrypted by default and it should only run on a trusted, secured host.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$How is Paperless-ngx different from Papermerge?$q$, $q$Both are open-source, self-hosted document management tools; Paperless-ngx focuses on lightweight simplicity for individuals and small teams, while Papermerge emphasizes multi-user permissions and an API-first design.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Does Paperless-ngx support mobile document capture?$q$, $q$Yes, documents can be added via companion mobile apps and email ingestion.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Digitizing home paperwork$q$, $q$Scan and archive bills, receipts and contracts into a searchable personal document library.$q$, $q$Individuals and home-lab users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Privacy-focused small business archive$q$, $q$Run a self-hosted document archive without relying on a third-party cloud SaaS.$q$, $q$Small businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Internal document search system$q$, $q$Build an on-premises, searchable document repository for IT-managed infrastructure.$q$, $q$IT teams and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A - self-hosted, no subscription$q$, NULL, $q$["GPL-3.0 licensed source code","Unlimited documents and users","Community support via GitHub and Matrix chat","Requires own server or hosting infrastructure"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Paperless-ngx is a free, open-source, self-hosted document management system licensed under GPL-3.0, with more than 43,000 stars on GitHub. It is a community-maintained fork created in early 2022 after the earlier Paperless-ng project's original maintainer stepped back.$q$, $q$The lineage traces back further: the original Paperless project was created by Daniel Quinn around 2017, then rewritten into Paperless-ng by Jonas Winkler in 2019, before the community forked it into Paperless-ngx to spread maintenance across a team of contributors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Paperless-ngx watches a consume folder, or accepts uploads by web, email or mobile app, then automatically runs OCR on incoming documents and uses machine-learning-assisted classification to suggest tags, correspondents, document types and dates.$q$, $q$All OCR'd text is fully searchable through the web interface, and the system supports document versioning, a REST API for automation, and multi-user access, all while running entirely on infrastructure the user controls.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Paperless-ngx is completely free and open source, with no subscription fee or paid tier. There are no vendor licensing costs because anyone can self-host it using the publicly available source code and Docker images.$q$, $q$The real cost of running Paperless-ngx is infrastructure and time: users need a server, NAS or cloud VM to host it, along with ongoing responsibility for backups, updates and securing the deployment, since it is not offered as a managed SaaS product by its maintainers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('833af197-f585-45d4-b9f9-cf879adb35d4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$OCR text extraction$q$, $q$Extract and overlay searchable text on scanned documents automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Dual-panel document browser$q$, $q$Navigate and organize documents with drag-and-drop across two panels.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Hierarchical folders and tags$q$, $q$Organize documents with nested folders, tags and custom metadata fields.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$RESTful API$q$, $q$Automate document workflows through an OpenAPI-compliant REST API.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Multi-user permissions$q$, $q$Share documents and folders across users and groups with granular access control.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Document versioning$q$, $q$Track revisions and manage individual pages, including deleting, reordering and extracting pages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Full-text search$q$, $q$Search across OCR'd document content, not just filenames or metadata.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Multi-format support$q$, $q$Import and manage PDF, TIFF, JPEG and PNG documents.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Free and open source under the permissive Apache-2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$API-first design makes it easy to automate and integrate$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Multi-user permissions and sharing suited to small teams, not just individuals$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Self-hosted, giving full control over data and privacy$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Modern tech stack with a Python backend, TypeScript frontend and PostgreSQL database$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Much smaller community and slower feature velocity than Paperless-ngx$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Requires self-hosting expertise, including Docker and server maintenance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Less mature auto-tagging and machine-learning features than some competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Documentation and third-party tutorials are sparser than more popular alternatives$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$No official commercial support or SLA$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$What is Papermerge?$q$, $q$A free, open-source, self-hosted document management system for scanning and organizing documents with OCR.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Is Papermerge free?$q$, $q$Yes, it is open source under the Apache-2.0 license with no licensing cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$How is Papermerge different from Paperless-ngx?$q$, $q$Both are self-hosted, open-source OCR document managers, but Papermerge uses the Apache-2.0 license and emphasizes an API-first, multi-user permission model, while Paperless-ngx has a much larger community and focuses on simplicity for individuals and small teams.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Does Papermerge have an API?$q$, $q$Yes, it offers a RESTful, OpenAPI-compliant API for automation and integrations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Do I need to self-host Papermerge?$q$, $q$Yes, it runs on your own server or infrastructure, typically via Docker.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Does Papermerge support multiple users?$q$, $q$Yes, with group ownership and sharing permissions.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$What file formats does Papermerge support?$q$, $q$PDF, TIFF, JPEG and PNG.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Is Papermerge actively maintained?$q$, $q$Yes, it continues to receive updates from its GitHub organization and community contributors.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$API-driven document workflows$q$, $q$Build custom document automation on top of Papermerge's REST API.$q$, $q$Developers and technical teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Permissioned team document sharing$q$, $q$Give a small team shared, permissioned access to a self-hosted document archive.$q$, $q$Small businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Personal scanned document archive$q$, $q$Digitize and organize personal paper records into a searchable system.$q$, $q$Individuals and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A - self-hosted, no subscription$q$, NULL, $q$["Apache-2.0 licensed source code","Unlimited documents and users","REST API access","Requires own server or hosting infrastructure"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Papermerge is a free, open-source, self-hosted document management system licensed under Apache-2.0, with development reportedly beginning around 2018. It is hosted on GitHub under the papermerge organization, evolving from the original ciur/papermerge repository.$q$, $q$It is frequently compared to Paperless-ngx, another self-hosted OCR document manager, but the two are separate projects with different licenses and communities; Papermerge is the smaller of the two, with a stronger focus on multi-user permissions and an API-first design.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Papermerge extracts text from scanned PDFs, TIFFs, JPEGs and PNGs using OCR, indexing that text for full-text search, and presents documents in a dual-panel browser with drag-and-drop organization, hierarchical folders, tags and custom metadata fields.$q$, $q$The system exposes a RESTful, OpenAPI-compliant API, supports multi-user access with group ownership and sharing permissions, and includes document versioning with page-level management such as deleting, reordering or extracting individual pages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Papermerge is completely free and open source under the Apache-2.0 license, with no subscription fee, paid tier or vendor licensing cost.$q$, $q$As with other self-hosted software, the practical cost comes from infrastructure: users need to provide and maintain their own server, commonly via Docker, and take on responsibility for backups, updates and security since there is no official managed hosting or paid support plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('094491bf-2c55-4e74-8744-920a4c1860d4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
