INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$What is Papertrail used for?$q$, $q$Aggregating, searching and monitoring log data from servers, applications and cloud services in real time.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Who owns Papertrail?$q$, $q$SolarWinds, which acquired Papertrail in 2015 for $41 million.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Is Papertrail free?$q$, $q$Yes, a free plan offers 50MB/month with 48-hour retention; paid plans start at about $7/month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$When was Papertrail founded?$q$, $q$2011, in Seattle, by Troy Davis and Eric Lindvall.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Does Papertrail support alerting?$q$, $q$Yes, alerts can be configured based on log patterns or thresholds.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$How is Papertrail different from Datadog or Splunk?$q$, $q$Papertrail focuses specifically on simple, fast log aggregation and search, while Datadog and Splunk offer broader observability suites including metrics, traces and APM.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$How long does Papertrail retain logs?$q$, $q$Most plans include 7-day searchable retention, with longer-term archiving options available.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Does Papertrail have an API?$q$, $q$Yes, it offers an API and command-line tools for programmatic access to log data.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Centralized logging for a small application$q$, $q$Aggregate logs from a small number of servers or services into one searchable stream.$q$, $q$Developers and small engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Real-time troubleshooting$q$, $q$Use live tailing to watch logs during deploys or incidents as they happen.$q$, $q$DevOps and SRE teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Log retention for compliance$q$, $q$Archive logs to external storage to meet audit or compliance retention requirements.$q$, $q$IT and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["50MB of logs per month","48-hour searchable retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Small$q$, $q$$7/month$q$, $q$monthly$q$, NULL, $q$["1GB of logs per month","7-day searchable retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Medium$q$, $q$$40/month$q$, $q$monthly$q$, NULL, $q$["10GB of logs per month","7-day searchable retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Large$q$, $q$$230/month$q$, $q$monthly$q$, NULL, $q$["100GB of logs per month","7-day searchable retention"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$annual contract$q$, NULL, $q$["500GB to 5TB+ of logs per month","Custom retention and archiving"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Papertrail is a cloud-hosted log management service founded in 2011 in Seattle by Troy Davis and Eric Lindvall. It was acquired by SolarWinds in 2015 for $41 million and now operates as a product within SolarWinds' broader IT management portfolio.$q$, $q$The service aggregates logs from servers, applications, network devices and cloud platforms into a single searchable, real-time stream, prioritizing fast setup and simplicity over the broader feature set of full observability platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Papertrail offers live tailing so engineers can watch logs arrive in real time, instant full-text search across recent and archived logs, and saved searches paired with alerting on specific patterns or thresholds.$q$, $q$Logs can be forwarded via syslog or a lightweight agent, and access controls let teams share visibility into the same log stream. An API and command-line tools support programmatic access, and logs can be archived to external storage for longer-term retention.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c326978a-2a64-44b7-a572-f9fb892fc271', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Papertrail's free plan covers 50MB of logs per month with 48-hour searchable retention. Paid plans scale by volume: Small is about $7/month for 1GB, Medium is $40/month for 10GB, and Large is $230/month for 100GB.$q$, $q$Enterprise pricing is custom for organizations logging from 500GB up to several terabytes per month. Most paid plans include seven-day searchable retention, with options to archive older logs to external storage for compliance or historical analysis.$q$]::text[], 2);
