-- ── Pantheon ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pantheon is a WebOps platform providing managed hosting, Git-based development workflows and operations automation for WordPress and Drupal websites.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$55/month (Basic Site Plan); free sandbox workspace available$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$400-500 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Pantheon Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pantheon is a WebOps hosting platform for WordPress and Drupal. Compare pricing plans, features, pros, cons and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pantheon is a WebOps platform founded in 2010 as Pantheon Systems and headquartered in San Francisco, California, providing managed cloud hosting, development workflow tools and operations automation specifically for WordPress and Drupal websites; the company has raised significant venture funding over its history and employs roughly 400 to 500 people. Rather than being a generic web host, Pantheon's core differentiator is its opinionated WebOps model, which gives every site standardized development, test and live environments, Git-based version control, a command-line interface called Terminus, automated backups, a built-in content delivery network, and multidev environments that let teams spin up isolated environments for feature branches, all designed to bring modern DevOps and CI/CD discipline to WordPress and Drupal deployments. Its pricing is subscription-based and combines two layers: a Workspace plan (Silver is free for sandbox sites; Gold and above add multidev, automated updates, visual regression testing and support) and per-site Site Plans priced by monthly visits and pages served, starting around 55 dollars per month for a Basic site and scaling through Performance Small, Medium, Large and XL tiers up to roughly 1,150 dollars per month, with custom Elite pricing for the highest-traffic, highest-SLA needs; annual billing typically includes additional traffic headroom. Pantheon targets digital agencies, enterprise marketing teams, and in-house web teams that manage many WordPress or Drupal sites and need consistent workflows, compliance (SOC 2, GDPR, FERPA) and uptime guarantees across a portfolio, rather than individual hobbyist site owners. Its most direct competitors include WP Engine, a managed WordPress-only host with a comparable agency and enterprise focus; Kinsta, another premium managed WordPress host known for its cloud infrastructure; Acquia, which competes most directly on the Drupal enterprise side; and generic enterprise hosting options like WordPress.com VIP. Pantheon differentiates itself from these competitors by being one of the few platforms that natively supports both WordPress and Drupal under one WebOps model with the same environment structure, multidev branching, and portfolio-level management tools, making it a common choice for agencies and enterprises running mixed CMS estates.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8dd02588-9e72-460d-8c15-9f28eeaf959d';

