-- ── Paperform ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Paperform is an online form and document builder with a flexible, word-processor-style editor for creating surveys, landing pages, quizzes and payment-enabled order forms.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $24/month)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Sydney, Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Paperform Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Paperform is a flexible online form builder for surveys, payments and landing pages. Compare pricing, features, pros, cons and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Paperform is an online form-building platform founded in 2016 by Dean and Diony McPherson and headquartered in Sydney, Australia; it is a bootstrapped, self-funded company that has stayed lean, reportedly operating with a small team of around 15 to 20 employees while generating single-digit millions in annual recurring revenue. Unlike grid-based form builders, Paperform's editor behaves more like a word processor or document, letting users type content and drop in form fields, images, videos and payment blocks inline, which makes it well suited for forms that double as landing pages, product pages, proposals or order forms rather than plain data-collection surveys. Key differentiators include its document-style WYSIWYG editor, a guided or conversational display mode similar to Typeform, an Excel-like calculation engine for building quotes, pricing and scored quizzes, native support for five payment gateways including Stripe and PayPal across all paid plans, and integrations with tools like Zapier, Google Sheets, Mailchimp and Slack. Paperform uses a freemium subscription pricing model: a free plan allows one user and 30 submissions per month, while paid tiers begin with Essentials at 24 dollars per month, moving through Pro at 49 dollars per month and Business at 99 dollars per month, with an Enterprise tier offering custom pricing, unlimited submissions and bespoke functionality; each tier raises submission limits, user seats, storage and feature access such as custom domains, custom HTML/CSS and single sign-on. The product targets small businesses, agencies, coaches, consultants and course creators who need a form that can also sell products, collect payments or replace a simple website page, as opposed to enterprise teams needing heavy compliance features. Its most cited competitors are Typeform, known for its one-question-at-a-time conversational format and polished design but more limited multi-field layouts and payment options; Jotform, which offers a much larger template library, more advanced conditional logic and PDF generation aimed at operational use cases; Google Forms, a free, simple option for basic surveys; and Tally, a newer minimalist form builder with a generous free tier. Paperform differentiates itself from these rivals by combining document-like design flexibility, built-in payment collection across multiple gateways on every paid plan, and calculation and quoting logic in one product, positioning it between the simplicity of Google Forms and the enterprise depth of Jotform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b3f994ed-6c32-4065-b748-3f9cadf0652e';

