-- ── Paperless-ngx ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Paperless-ngx is a free, open-source, self-hosted document management system that scans, OCRs, tags and indexes documents into a searchable digital archive.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$Not applicable - community-maintained open-source project$q$, company_size),
  headquarters = COALESCE($q$Not applicable - distributed open-source community$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$Dutch$q$, $q$French$q$, $q$Portuguese (Brazil)$q$]::text[],
  seo_title = COALESCE($q$Paperless-ngx Review 2026: Setup, Features, Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Paperless-ngx is a free, self-hosted document management system with OCR and full-text search. See features, setup basics and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Paperless-ngx is a free, open-source, self-hosted document management system that scans, OCRs, tags and archives physical and digital documents into a searchable online library; it runs under the GPL-3.0 license and has accumulated more than 43,000 stars on GitHub, making it one of the most popular self-hosted document management tools in the open-source ecosystem. The project has a multi-generational history: it began as Paperless, created by Daniel Quinn around 2017 as a Python tool for digitizing paper documents, was rewritten and modernized into Paperless-ng by Jonas Winkler starting in 2019 using Django, and was then forked again in early 2022 into Paperless-ngx by a group of community maintainers after Winkler stepped back from active development, explicitly to distribute maintenance responsibility across a team rather than a single person. Functionally, Paperless-ngx watches a designated folder, or accepts uploads via web, email or a mobile app, for incoming documents, runs OCR to extract text, and uses machine-learning-assisted classification to automatically suggest tags, correspondents, document types and dates, after which everything becomes searchable through a full-text index and a modern Angular/Django web interface. Because it is self-hosted, typically via Docker Compose, Paperless-ngx has no licensing cost, but it requires the user to provide their own server or NAS, manage backups, and secure the deployment themselves; the maintainers explicitly warn it should never be exposed on an untrusted host because documents are stored unencrypted by default. Its target users are privacy-conscious individuals, home-lab enthusiasts, small businesses and IT-savvy teams who want to digitize paper archives such as contracts, receipts and mail without relying on a third-party cloud SaaS. Its closest competitors are Papermerge, a similarly open-source, self-hosted OCR document manager under the Apache-2.0 license with a stronger emphasis on multi-user permissions and a REST API; Mayan EDMS, a more feature-heavy open-source DMS aimed at organizations needing complex workflow automation and role-based access control; and commercial SaaS document management platforms like DocuWare or M-Files for organizations that prefer a hosted, supported product over self-hosting. Paperless-ngx differentiates itself from these alternatives through its relatively lightweight resource footprint, large and active open-source community, and a strong reputation for ease of initial setup relative to heavier enterprise-oriented systems like Mayan EDMS.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '833af197-f585-45d4-b9f9-cf879adb35d4';

