  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Papermerge Review 2026: Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Papermerge is an open-source, self-hosted document management system with OCR and a REST API. Compare features and alternatives like Paperless-ngx.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Papermerge is a free, open-source, self-hosted document management system built to digitize and organize scanned documents, distributed under the Apache-2.0 license and hosted primarily on GitHub under the papermerge organization, with roots in the original ciur/papermerge repository; development reportedly began around 2018 when its creator started building the project after leaving full-time employment. The system extracts text from scans using OCR, indexes that text for full-text search, and organizes documents through a dual-panel file browser with drag-and-drop, hierarchical folders, tagging and custom metadata fields, supporting common formats such as PDF, TIFF, JPEG and PNG; it exposes a RESTful, OpenAPI-compliant API and is built on a Python backend with a TypeScript frontend and PostgreSQL database, making it straightforward to script or integrate with other systems. Papermerge is most frequently compared to, and confused with, Paperless-ngx, a similarly self-hosted, open-source OCR document manager, but the two projects have distinct codebases, licenses (Apache-2.0 for Papermerge versus GPL-3.0 for Paperless-ngx) and communities; Papermerge has generally positioned itself around multi-user access with group ownership and sharing permissions and an API-first design, while Paperless-ngx has a much larger community, over 40,000 GitHub stars versus roughly 500 for Papermerge, and leans toward simplicity for individual and small-team use with machine-learning-assisted auto-tagging. Because it is open source and self-hosted, Papermerge has no licensing fee, but users must provide and maintain their own server infrastructure, commonly via Docker, and are responsible for backups and security. Its target audience is individuals, small teams and developers who want full control and API access over a self-hosted document archive, particularly those who value permissioned multi-user sharing or plan to build custom integrations on top of the REST API. Its closest competitors are Paperless-ngx, the much more widely adopted alternative in the same self-hosted OCR document-management niche; Mayan EDMS, a heavier open-source DMS with more built-in workflow automation for larger organizations; and commercial hosted document management platforms like DocuWare or M-Files for teams unwilling to self-host. Papermerge differentiates itself through its API-centric architecture and permissioned multi-user model rather than trying to match Paperless-ngx's larger community or Mayan EDMS's workflow depth.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '094491bf-2c55-4e74-8744-920a4c1860d4';

